```class Solution {
public:
    int largestInteger(int num) {
        int result = num;
        while (true) {
            if (is_even(result)) {
                swap_digits(result);
            } else {
                break;
            }
        }
        return result;
    }

    bool is_even(int num) {
        return (num % 2 == 0);
    }

    void swap_digits(int num) {
        int temp = num % 10;
        num /= 10;
        num *= 10;
        num += temp;
    }
};
